descriptor.templateCss:
/* Sensor Debug Panel */
.dbg-container {
    width: 100%;
    height: 100%;
    display: flex;
    flex-direction: column;
    background: rgba(3, 18, 28, 0.9);
    border: 1px solid rgba(0, 220, 255, 0.25);
    border-radius: 8px;
    font-family: 'Segoe UI', 'PingFang SC', 'Microsoft YaHei', sans-serif;
    color: #c0d8e8;
    overflow: hidden;
    backdrop-filter: blur(10px);
}

.dbg-header {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 10px 14px;
    border-bottom: 1px solid rgba(0, 220, 255, 0.15);
    background: rgba(0, 0, 0, 0.2);
}

.dbg-header-icon { font-size: 16px; }
.dbg-header-title { font-size: 14px; font-weight: 600; color: #e0f0ff; }
.dbg-header-hint { font-size: 11px; color: #5a8a70; margin-left: auto; }

.dbg-body {
    flex: 1;
    padding: 12px 14px;
    overflow-y: auto;
}

.dbg-row {
    background: rgba(0, 0, 0, 0.18);
    border: 1px solid rgba(0, 217, 255, 0.1);
    border-radius: 6px;
    padding: 12px;
    margin-bottom: 10px;
}

.dbg-label {
    display: flex;
    align-items: center;
    gap: 6px;
    margin-bottom: 8px;
}

.dbg-icon { font-size: 16px; }
.dbg-name { font-size: 13px; font-weight: 500; color: #c0d8e8; }
.dbg-unit { font-size: 11px; color: #5a8a70; }

.dbg-slider-wrap {
    display: flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 6px;
}

.dbg-slider {
    flex: 1;
    -webkit-appearance: none;
    appearance: none;
    height: 6px;
    border-radius: 3px;
    background: rgba(0, 220, 255, 0.2);
    outline: none;
    cursor: pointer;
}

.dbg-slider::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: #00d9ff;
    border: 2px solid #020b12;
    cursor: pointer;
    box-shadow: 0 0 8px rgba(0, 217, 255, 0.5);
}

.dbg-slider::-moz-range-thumb {
    width: 16px;
    height: 16px;
    border-radius: 50%;
    background: #00d9ff;
    border: 2px solid #020b12;
    cursor: pointer;
    box-shadow: 0 0 8px rgba(0, 217, 255, 0.5);
}

.dbg-value {
    min-width: 32px;
    text-align: right;
    font-family: 'Courier New', monospace;
    font-size: 18px;
    font-weight: 700;
    color: #00d9ff;
}

.dbg-threshold {
    font-size: 10px;
    color: #4a6a80;
    margin-bottom: 8px;
}

.dbg-actions {
    display: flex;
    gap: 6px;
}

.dbg-btn {
    padding: 5px 14px;
    border-radius: 4px;
    border: 1px solid rgba(0, 220, 255, 0.2);
    background: rgba(0, 0, 0, 0.3);
    color: #7a9ab0;
    font-size: 12px;
    cursor: pointer;
    transition: all 0.2s;
    font-family: inherit;
}

.dbg-btn:hover {
    border-color: rgba(0, 220, 255, 0.4);
    background: rgba(0, 220, 255, 0.08);
    color: #c0e0f0;
}

.dbg-btn-apply {
    border-color: rgba(53, 242, 143, 0.3);
    color: #35f28f;
}

.dbg-btn-apply:hover {
    background: rgba(53, 242, 143, 0.1);
    border-color: rgba(53, 242, 143, 0.5);
}

.dbg-btn-clear {
    border-color: rgba(255, 149, 0, 0.2);
    color: #7a6a50;
}

.dbg-btn-clear:hover {
    border-color: rgba(255, 149, 0, 0.4);
    color: #ff9500;
}

.dbg-footer {
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 8px 14px;
    border-top: 1px solid rgba(0, 220, 255, 0.12);
    background: rgba(0, 0, 0, 0.15);
}

.dbg-btn-clear-all {
    border-color: rgba(255, 56, 96, 0.2);
    color: #8a5a60;
}

.dbg-btn-clear-all:hover {
    border-color: rgba(255, 56, 96, 0.4);
    color: #ff3860;
    background: rgba(255, 56, 96, 0.06);
}

.dbg-status {
    margin-left: auto;
    font-size: 11px;
    color: #4a6a80;
    font-family: 'Courier New', monospace;
}

.dbg-status.dbg-ok { color: #35f28f; }
.dbg-status.dbg-err { color: #ff3860; }

descriptor.controllerScript:
/**
 * ThingsBoard Debug Sensor Panel
 * 传感器调试控制台 — 覆盖模拟器数据，快速触发联动
 */

var DEVICE_ID = '2d415ac0-5803-11f1-928b-253a5007835b';
var els = {};
var currentOverrides = {};

function setStatus(text, isError) {
    if (els.status) {
        els.status.textContent = text;
        els.status.className = 'dbg-status' + (isError ? ' dbg-err' : ' dbg-ok');
    }
}

function sendRpc(method, params) {
    if (!self.ctx || !self.ctx.http) {
        console.warn('[Debug] http not available');
        setStatus('HTTP 不可用', true);
        return;
    }
    console.log('[Debug] ' + method, params);
    self.ctx.http.post('/api/rpc/oneway/' + DEVICE_ID, {
        method: method,
        params: params
    }).subscribe(
        function() {
            setStatus('成功: ' + method);
            console.log('[Debug] OK: ' + method);
        },
        function(err) {
            setStatus('失败: ' + method, true);
            console.error('[Debug] FAIL: ' + method, err);
        }
    );
}

function cacheElements(container) {
    var q = function(s) { return container.querySelector(s); };
    els = {
        slider: q('#dbg-soilHumidity'),
        value: q('#dbg-val-soilHumidity'),
        status: q('#dbg-status'),
        applyBtns: container.querySelectorAll('.dbg-btn-apply'),
        clearBtns: container.querySelectorAll('.dbg-btn-clear'),
        clearAllBtn: q('.dbg-btn-clear-all')
    };
}

self.onInit = function() {
    console.log('[Debug Panel] Initializing...');
    var $el = self.ctx.$container[0] || self.ctx.$container;
    cacheElements($el);

    // Slider value display
    if (els.slider && els.value) {
        els.slider.addEventListener('input', function() {
            els.value.textContent = this.value;
        });
    }

    // Apply button: send setDebugSensor RPC
    for (var i = 0; i < els.applyBtns.length; i++) {
        els.applyBtns[i].addEventListener('click', function() {
            var key = this.dataset.key;
            var val = parseFloat(document.getElementById('dbg-' + key).value);
            sendRpc('setDebugSensor', { key: key, value: val });
            currentOverrides[key] = val;
            console.log('[Debug] Override ' + key + ' = ' + val);
        });
    }

    // Clear button: send clearDebugSensor RPC
    for (var j = 0; j < els.clearBtns.length; j++) {
        els.clearBtns[j].addEventListener('click', function() {
            var key = this.dataset.key;
            sendRpc('clearDebugSensor', { key: key });
            delete currentOverrides[key];
            console.log('[Debug] Clear ' + key);
        });
    }

    // Clear all button
    if (els.clearAllBtn) {
        els.clearAllBtn.addEventListener('click', function() {
            sendRpc('clearAllDebugSensors', {});
            currentOverrides = {};
            console.log('[Debug] Clear all');
        });
    }

    setStatus('就绪');
    console.log('[Debug Panel] Ready');
};

self.onDataUpdated = function() {
    // Read current soilHumidity from telemetry to sync slider
    if (!self.ctx || !self.ctx.data || !els.slider) return;
    for (var i = 0; i < self.ctx.data.length; i++) {
        var dk = self.ctx.data[i];
        if (dk.dataKey && dk.dataKey.name === 'soilHumidity' && dk.data && dk.data.length > 0) {
            var last = dk.data[dk.data.length - 1];
            var val = parseFloat(last.length > 1 ? last[1] : last[0]);
            if (!isNaN(val) && !currentOverrides['soilHumidity']) {
                els.slider.value = Math.round(val);
                if (els.value) els.value.textContent = Math.round(val);
            }
        }
    }
};

self.onDestroy = function() {
    console.log('[Debug Panel] Destroyed');
};
